import React, { useState, useContext } from 'react';
import AdminLayout from '../../components/Layouts/AdminLayout';
import { DataContext } from '../../context/DataContext';
import { AuthContext } from '../../context/AuthContext';
import { ROLES, formatDate } from '../../utils/helpers';

const DisciplineManager = () => {
  const { 
    disciplineTypes, addDisciplineType, updateDisciplineTypeStatus,
    disciplineRecords, requestDeleteDisciplineRecord, approveDeleteDisciplineRecord,
    staffList 
  } = useContext(DataContext);
  const { user } = useContext(AuthContext);

  const [newDiscipline, setNewDiscipline] = useState('');

  // Quyền hạn
  const isRegulatory = user.role === ROLES.REGULATORY_ADMIN;
  const isOperational = user.role === ROLES.OPERATIONAL_ADMIN;
  const isChief = user.role === ROLES.CHIEF_ADMIN;

  const handleAddDiscipline = () => {
    if (!newDiscipline) return;
    // Regulatory -> Approved ngay, Operational -> Pending
    const status = isRegulatory ? 'Approved' : 'Pending';
    addDisciplineType({ name: newDiscipline, status, createdBy: user.role });
    setNewDiscipline('');
  };

  return (
    <AdminLayout>
      <div className="p-4 space-y-6">
        <h2 className="text-2xl font-bold">Quản lý Kỷ luật</h2>

        {/* 1. Khu vực Danh sách hình thức kỷ luật (Ban hành & Đề xuất) */}
        <div className="bg-white p-4 rounded shadow">
          <h3 className="font-bold text-lg mb-2 border-b pb-2">Danh mục hình thức kỷ luật</h3>
          
          {(isRegulatory || isOperational) && (
            <div className="flex gap-2 mb-4">
              <input 
                type="text" placeholder="Tên hình thức kỷ luật..." className="border p-2 flex-1"
                value={newDiscipline} onChange={e => setNewDiscipline(e.target.value)}
              />
              <button onClick={handleAddDiscipline} className="bg-red-600 text-white px-4 py-2 rounded">
                {isRegulatory ? 'Ban hành' : 'Đề xuất'}
              </button>
            </div>
          )}

          <table className="w-full text-sm">
            <thead>
              <tr className="bg-gray-100 text-left"><th className="p-2">Tên</th><th className="p-2">Nguồn</th><th className="p-2">Trạng thái</th><th className="p-2">Hành động</th></tr>
            </thead>
            <tbody>
              {disciplineTypes.map(d => (
                <tr key={d.id} className="border-b">
                  <td className="p-2">{d.name}</td>
                  <td className="p-2">{d.createdBy}</td>
                  <td className="p-2">
                    <span className={`px-2 py-1 rounded text-xs ${
                      d.status === 'Approved' ? 'bg-green-100 text-green-800' :
                      d.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' : 'bg-gray-200'
                    }`}>
                      {d.status === 'Approved' ? 'Đã duyệt' : d.status === 'Pending' ? 'Chờ duyệt' : d.status}
                    </span>
                  </td>
                  <td className="p-2">
                    {/* Regulatory Admin duyệt các đề xuất của Operational */}
                    {isRegulatory && d.status === 'Pending' && (
                      <button onClick={() => updateDisciplineTypeStatus(d.id, 'Approved')} className="text-blue-600 mr-2 hover:underline">Duyệt</button>
                    )}
                    {isRegulatory && d.status === 'Approved' && (
                       <button onClick={() => updateDisciplineTypeStatus(d.id, 'Suspended')} className="text-red-600 hover:underline">Đình chỉ</button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* 2. Khu vực Nhân sự đang chịu kỷ luật (Yêu cầu 2) */}
        <div className="bg-white p-4 rounded shadow">
          <h3 className="font-bold text-lg mb-2 text-red-700 border-b pb-2">Danh sách nhân sự đang bị kỷ luật</h3>
          <table className="w-full text-sm">
            <thead>
              <tr className="bg-red-50 text-left">
                <th className="p-2">Nhân sự</th>
                <th className="p-2">Vi phạm</th>
                <th className="p-2">Hình thức xử lý</th>
                <th className="p-2">Thời gian</th>
                <th className="p-2">Trạng thái</th>
                <th className="p-2">Hành động</th>
              </tr>
            </thead>
            <tbody>
              {disciplineRecords.map(rec => {
                const staff = staffList.find(s => s.id === rec.staffId);
                const type = disciplineTypes.find(t => t.id == rec.disciplineId);
                return (
                  <tr key={rec.id} className="border-b hover:bg-gray-50">
                    <td className="p-2 font-medium">{staff?.name}</td>
                    <td className="p-2">{rec.violation}</td>
                    <td className="p-2 text-red-600">{type?.name}</td>
                    <td className="p-2">{formatDate(rec.date)}</td>
                    <td className="p-2">{rec.status === 'Pending_Deletion' ? 'Chờ xóa' : 'Đang thi hành'}</td>
                    <td className="p-2">
                      {/* Regulatory đề xuất xóa */}
                      {isRegulatory && rec.status === 'Active' && (
                        <button onClick={() => requestDeleteDisciplineRecord(rec.id)} className="text-orange-600 hover:underline">Đề xuất xóa</button>
                      )}
                      {/* Chief duyệt xóa */}
                      {isChief && rec.status === 'Pending_Deletion' && (
                        <button onClick={() => approveDeleteDisciplineRecord(rec.id)} className="text-green-600 hover:underline font-bold">Chấp thuận xóa</button>
                      )}
                    </td>
                  </tr>
                );
              })}
              {disciplineRecords.length === 0 && <tr><td colSpan="6" className="p-4 text-center text-gray-500">Không có nhân sự nào đang bị kỷ luật</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </AdminLayout>
  );
};

export default DisciplineManager;
